/// Contains one field from one log event returned by a CloudWatch Logs Insights
/// query, along
/// with the value of that field.
///
/// For more information about the fields that are generated by CloudWatch logs,
/// see [Supported
/// Logs and Discovered
/// Fields](https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/CWL_AnalyzeLogData-discoverable-fields.html).
pub const ResultField = struct {
    /// The log event field.
    field: ?[]const u8,

    /// The value of this field.
    value: ?[]const u8,

    pub const json_field_names = .{
        .field = "field",
        .value = "value",
    };
};
